static void launch_user(uint64 entry)
{
    asm volatile(
        "csrw sepc, %[entry]\n"
        "li t0, 0x40020\n"
        "csrw sstatus, t0\n"
        "sret\n"
        :
        : [entry] "r"(entry)
        : "t0", "memory"
    );
}

static void run_test(void)
{
    struct proc *p = proc_alloc();
    if (!p) return;

    p->pgtbl = uvm_create();
    if (!p->pgtbl) return;

    uint64 *kpgtbl = get_kernel_pgtbl();
    p->pgtbl[2] = kpgtbl[2];
    p->pgtbl[0] = kpgtbl[0];

    void *code = kalloc_page();
    if (!code) return;
    for (int i = 0; i < 64; i++) ((char *)code)[i] = test_bin[i];
    uvm_map(p->pgtbl, 0x1000, (uint64)code, PAGE_SIZE, PTE_R|PTE_W|PTE_X|PTE_U);

    void *stack = kalloc_page();
    if (!stack) return;
    uvm_map(p->pgtbl, USTACK_TOP - PAGE_SIZE, (uint64)stack, PAGE_SIZE, PTE_R|PTE_W|PTE_U);

    p->tf = (struct trapframe *)((uint64)p->kstack + 4096 - 272);
    for (int i = 0; i < (int)(sizeof(struct trapframe) / 8); i++)
        ((uint64 *)p->tf)[i] = 0;
    p->tf->sepc = 0x1000;
    p->tf->sp = USTACK_TOP;
    p->tf->sstatus = (1 << 5);

    curr_proc = p;
    uint64 ksp = (uint64)p->kstack + 4096;
    uint64 satp = ((uint64)p->pgtbl >> 12) | (8UL << 60);

    // uart_puts before sret is required - provides necessary delay for TLB
    uart_puts("");
    asm volatile(
        "csrw sscratch, %[ksp]\n"
        "csrw satp, %[satp]\n"
        "sfence.vma\n"
        "csrw sepc, %[entry]\n"
        "li t0, 0x40020\n"
        "csrw sstatus, t0\n"
        "sret\n"
        :
        : [ksp] "r"(ksp), [satp] "r"(satp), [entry] "r"(0x1000ULL)
        : "t0", "t1", "memory"
    );
}

