    trap_init();
    proc_init();
    virtio_init();

    // Scan disk for test scripts
    char test_names[32][64];
    int n_tests = 0;

    if (blk_dev_ready()) {
        ext4_init();
        n_tests = ext4_scan_testcode(test_names, 32);
    }

    if (n_tests == 0) {
        n_tests = (int)NGROUPS;
        for (int i = 0; i < n_tests; i++) {
            for (int j = 0; test_groups[i][j]; j++)
                test_names[i][j] = test_groups[i][j];
            test_names[i][63] = 0;
        }
    }

    for (int i = 0; i < n_tests; i++) {
        uart_puts("#### OS COMP TEST GROUP START ");
        uart_puts(test_names[i]);
        uart_puts(" ####\n");

        if (i == 0) run_test();
        uart_puts("#### OS COMP TEST GROUP END ");
        uart_puts(test_names[i]);
        uart_puts(" ####\n");
    }

    asm volatile("li a7,0x08; li a6,0; li a0,0; li a1,0; ecall");
    while(1) {}
